    val normalizedChars = new Array[Char](L)
    var i = 0
    for (j <- 0 until L) {
        val char = s(j)

        if (isLetter(char) || char == ' ') {
            normalizedChars(i) = char
            i += 1
        } else if (char == '-') {
            // Check if the hyphen is surrounded by letters in the original string s
            val leftNeighborIsLetter = j > 0 && isLetter(s(j - 1))
            val rightNeighborIsLetter = j < L - 1 && isLetter(s(j + 1))

            if (leftNeighborIsLetter && rightNeighborIsLetter) {
                // Valid hyphen
